module master_slave_d_latch(  
    input D,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
    reg unused_master;  
    always @(posedge CLK) begin  
        unused_master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= unused_master;  
        Qn <= ~unused_master;  
    end  
endmodule
